```c
#include <stdio.h>

int main() {
    int a, b, c;
    scanf("%d %d %d", &a, &b, &c);
    int rings = 0;

    for (int ring = 0; ring < c; ring++) {
        rings += (2 * a + 2 * b - 4);
        a -= 4;
        b -= 4;
    }

    printf("%d\n", rings);
    return 0;
}
